// Generated by AI (UnitTest MCP)
import { describe, expect, it } from "vitest";

import {
  boardRows,
  conformanceDiagnostic,
  evidenceRequestForTask,
  parseToolResult,
  resolveBinaryPath,
  resolveServerPath,
  toArtifactId,
} from "./util";

describe("toArtifactId", () => {
  it("normalises backslashes to forward slashes", () => {
    expect(toArtifactId("src\\auth.ts")).toBe("artifact:src/auth.ts");
  });

  it("leaves posix paths unchanged", () => {
    expect(toArtifactId("src/auth.ts")).toBe("artifact:src/auth.ts");
  });
});

describe("parseToolResult", () => {
  it("parses JSON from the first text content block", () => {
    const result = { content: [{ type: "text", text: '{"nodes":2}' }] };
    expect(parseToolResult(result)).toEqual({ nodes: 2 });
  });

  it("returns the raw text when it is not JSON", () => {
    const result = { content: [{ type: "text", text: "not json" }] };
    expect(parseToolResult(result)).toBe("not json");
  });

  it("returns the whole result when there is no text block", () => {
    const result = { content: [] };
    expect(parseToolResult(result)).toBe(result);
  });
});

describe("resolveServerPath", () => {
  it("honours an explicit non-default configured path", () => {
    expect(resolveServerPath("/custom/mindleak-mcp", "/ws", { exists: () => true })).toBe(
      "/custom/mindleak-mcp"
    );
  });

  it("prefers a release build when it exists (win32)", () => {
    const resolved = resolveServerPath("mindleak-mcp", "C:/ws", {
      platform: "win32",
      exists: (p) => p.includes("release"),
    });
    expect(resolved).toContain("release");
    expect(resolved).toContain("mindleak-mcp.exe");
  });

  it("falls back to debug when release is absent", () => {
    const resolved = resolveServerPath("mindleak-mcp", "/ws", {
      platform: "linux",
      exists: (p) => p.includes("debug"),
    });
    expect(resolved).toContain("debug");
    expect(resolved.endsWith("mindleak-mcp")).toBe(true);
  });

  it("falls back to the bare command when no build is found", () => {
    expect(resolveServerPath("mindleak-mcp", "/ws", { exists: () => false })).toBe("mindleak-mcp");
  });
});

describe("resolveBinaryPath", () => {
  it("resolves a workspace lodestar build (linux)", () => {
    const resolved = resolveBinaryPath("lodestar-mcp", "/ws", "lodestar-mcp", {
      platform: "linux",
      exists: (p) => p.includes("release"),
    });
    expect(resolved).toContain("release");
    expect(resolved.endsWith("lodestar-mcp")).toBe(true);
  });

  it("honours an explicit non-default path", () => {
    expect(
      resolveBinaryPath("/opt/lodestar-mcp", "/ws", "lodestar-mcp", { exists: () => true })
    ).toBe("/opt/lodestar-mcp");
  });
});

describe("boardRows", () => {
  it("orders by lifecycle and formats the owner", () => {
    const rows = boardRows([
      { id: "t1", goal_id: "g", title: "done thing", status: "done" },
      { id: "t2", goal_id: "g", title: "mine", status: "claimed", owner: "alice" },
    ]);
    expect(rows[0].label).toBe("mine");
    expect(rows[0].description).toBe("claimed \u00b7 alice");
    expect(rows[1].status).toBe("done");
  });
});

describe("conformanceDiagnostic", () => {
  it("returns null when aligned", () => {
    expect(conformanceDiagnostic({ verdict: "aligned", findings: [] })).toBeNull();
  });

  it("maps violation to error and drift to warning", () => {
    expect(conformanceDiagnostic({ verdict: "violation", findings: ["x"] })?.severity).toBe(
      "error"
    );
    expect(conformanceDiagnostic({ verdict: "drift", findings: [] })?.severity).toBe("warning");
  });
});

describe("evidenceRequestForTask", () => {
  it("uses the owner and stable claim window", () => {
    expect(
      evidenceRequestForTask(
        {
          id: "task:auth",
          goal_id: "goal:auth",
          title: "Harden auth",
          status: "claimed",
          owner: "agent-a",
          claim_started_at: 100,
        },
        "fallback",
        150
      )
    ).toEqual({
      task_id: "task:auth",
      agent_id: "agent-a",
      started_at: 100,
      ended_at: 150,
    });
  });

  it("rejects an unclaimed task or missing claim window", () => {
    expect(() =>
      evidenceRequestForTask(
        { id: "task:x", goal_id: "goal:x", title: "x", status: "open" },
        "agent-a",
        150
      )
    ).toThrow("not claimed");
    expect(() =>
      evidenceRequestForTask(
        { id: "task:x", goal_id: "goal:x", title: "x", status: "claimed" },
        "agent-a",
        150
      )
    ).toThrow("no claim start");
  });
});
